using OpenQA.Selenium;

namespace LeafTaps.Pages
{
    /// <summary>
    /// Page object generated strictly from the supplied HTML DOM for EditLeadPage.
    /// </summary>
    public class EditLeadPage
    {
        private readonly IWebDriver driver;

        public EditLeadPage(IWebDriver driver)
        {
            this.driver = driver;
        }

        private IWebElement CompanyNameInput => driver.FindElement(By.Id("createLeadForm_companyName"));
        private IWebElement FirstNameInput => driver.FindElement(By.Id("createLeadForm_firstName"));
        private IWebElement LastNameInput => driver.FindElement(By.Id("createLeadForm_lastName"));
        private IWebElement CreateLeadButton => driver.FindElement(By.XPath("//input[@value='Create Lead']"));

        /// <summary>
        /// Enters a value in the companyName field.
        /// </summary>
        public EditLeadPage EnterCompanyName(string companyName)
        {
            CompanyNameInput.Clear();
            CompanyNameInput.SendKeys(companyName);
            return this;
        }

        /// <summary>
        /// Enters a value in the firstName field.
        /// </summary>
        public EditLeadPage EnterFirstName(string firstName)
        {
            FirstNameInput.Clear();
            FirstNameInput.SendKeys(firstName);
            return this;
        }

        /// <summary>
        /// Enters a value in the lastName field.
        /// </summary>
        public EditLeadPage EnterLastName(string lastName)
        {
            LastNameInput.Clear();
            LastNameInput.SendKeys(lastName);
            return this;
        }

        /// <summary>
        /// Clicks the Create Lead element.
        /// </summary>
        public EditLeadPage ClickCreateLead()
        {
            CreateLeadButton.Click();
            return this;
        }
    }
}

